// Connect: register cron job + leader-aware goroutine
func (in *myInput) Connect(ctx context.Context) error {
	_, err := in.scheduler.NewJob(gocron.CronJob(in.schedule, true), gocron.NewTask(func(ctx context.Context) error {
		in.mu.Lock(); in.store[time.Now()] = in.fetchResults(ctx); in.mu.Unlock(); return nil
	}), gocron.WithContext(ctx))
	if err != nil { return err }
	go func() {
		running := false
		for { select {
		case <-ctx.Done(): if running { _ = in.scheduler.StopJobs() }; return
		case <-time.After(1 * time.Second):
			if leaderelection.IsLeader(in.resources) && !running { in.scheduler.Start(); running = true }
			if !leaderelection.IsLeader(in.resources) && running { _ = in.scheduler.StopJobs(); running = false }
		} }
	}()
	return nil
}
// ReadBatch: drain store with nack-restore
func (in *myInput) ReadBatch(ctx context.Context) (service.MessageBatch, service.AckFunc, error) {
	if !leaderelection.IsLeader(in.resources) { return nil, func(context.Context, error) error { return nil }, nil }
	in.mu.Lock(); defer in.mu.Unlock()
	processing := make(map[time.Time][]Result)
	var batch service.MessageBatch
	for t, results := range in.store {
		for _, r := range results {
			b, _ := json.Marshal(r); msg := service.NewMessage(b)
			msg.MetaSet("scrape_time", t.Format(time.RFC3339))
			batch = append(batch, msg)
		}
		processing[t] = results; delete(in.store, t)
	}
	return batch, func(ctx context.Context, err error) error {
		if err != nil { in.mu.Lock(); defer in.mu.Unlock(); for t := range processing { in.store[t] = processing[t] } }
		return nil
	}, nil
}

